import{_ as o}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as s,c,f as n,q as e,D as p,N as i,j as u,g as l,k as t,W as h}from"./chunks/runtime-core.esm-bundler.DuRo-bNR.js";const A=JSON.parse('{"title":"什么是提示词工程","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/什么是提示词工程.md","filePath":"column/AIFuture/基础认知/什么是提示词工程.md","lastUpdated":1782975799000}'),b={name:"column/AIFuture/基础认知/什么是提示词工程.md"};function m(k,a,g,v,E,q){const r=s("ArticleMetadata"),d=s("Mermaid");return n(),c("div",null,[a[1]||(a[1]=e("h1",{id:"什么是提示词工程",tabindex:"-1"},[l("什么是提示词工程 "),e("a",{class:"header-anchor",href:"#什么是提示词工程","aria-label":'Permalink to "什么是提示词工程"'},"​")],-1)),p(r),a[2]||(a[2]=i(`<p>先说结论：提示词工程不是什么玄学，也不是在写什么神秘咒语。</p><p>你刷到过那种「30 个让你效率翻倍的 Prompt 模板」吧？我也刷到过。但实际用起来就会发现，光抄模板根本解决不了问题——模板是别人的场景，你的任务是另一回事。</p><p>那提示词工程到底是什么？</p><p>其实就是<strong>把你脑子里的需求，用模型能稳定理解的方式说出来</strong>。不是什么高深的学术概念，就是一个&quot;把话说清楚&quot;的动作。只不过我们平时和人说话靠默契、靠上下文、靠&quot;你懂的&quot;，跟模型不行，它真的会瞎猜。</p><h2 id="你有没有遇到过这种情况" tabindex="-1">你有没有遇到过这种情况？ <a class="header-anchor" href="#你有没有遇到过这种情况" aria-label="Permalink to &quot;你有没有遇到过这种情况？&quot;">​</a></h2><p>对着 AI 说一句：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我优化一下这段代码</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后它改了，但改的是可读性，而你想要的是性能。</p><p>你说：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写个周报</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后它洋洋洒洒写了一篇，跟你实际做的事毫无关系。</p><p>问题不在模型笨，而在于我们没说清楚。就像你跟同事说&quot;帮我做一下那个&quot;，同事一定一脸懵。但你对 AI 这样说的时候，反而期待它猜到，这不是挺奇怪的嘛。</p><h2 id="那怎么写才算-说清楚-一个模板就够了" tabindex="-1">那怎么写才算&quot;说清楚&quot;？一个模板就够了 <a class="header-anchor" href="#那怎么写才算-说清楚-一个模板就够了" aria-label="Permalink to &quot;那怎么写才算&quot;说清楚&quot;？一个模板就够了&quot;">​</a></h2><p>不用看那些花里胡哨的框架，真正好用的就六件事：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 你是谁 → 让模型知道用什么角色回答</span></span>
<span class="line"><span>2. 要干嘛 → 目标是什么</span></span>
<span class="line"><span>3. 背景是啥 → 现有材料、业务上下文</span></span>
<span class="line"><span>4. 别干嘛 → 约束条件</span></span>
<span class="line"><span>5. 怎么输出 → 格式、长度、结构</span></span>
<span class="line"><span>6. 怎么算对 → 验收标准</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>套个例子你就明白了，还是刚才那个&quot;帮我优化代码&quot;，改成这样说：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是 Vue 前端开发。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>目标：在不改外部 API 的前提下优化这个组件的可读性。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>约束：</span></span>
<span class="line"><span>- 不新增依赖</span></span>
<span class="line"><span>- 不改 props 和 emit 名称</span></span>
<span class="line"><span>- 保留现有 CSS class</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出：</span></span>
<span class="line"><span>修改后的代码 + 改动原因 + 3 个需要跑的验证命令</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>这样写出来，模型基本不会跑偏。不是因为更&quot;长&quot;了，而是因为把那些你脑子里觉得&quot;不言自明&quot;的东西写出来了。</p><h2 id="几个实际场景的例子" tabindex="-1">几个实际场景的例子 <a class="header-anchor" href="#几个实际场景的例子" aria-label="Permalink to &quot;几个实际场景的例子&quot;">​</a></h2><h3 id="让-ai-帮你写文章" tabindex="-1">让 AI 帮你写文章 <a class="header-anchor" href="#让-ai-帮你写文章" aria-label="Permalink to &quot;让 AI 帮你写文章&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是技术博主。面向前端同学解释 RAG。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求：</span></span>
<span class="line"><span>- 先用一个生活类比讲清楚是什么</span></span>
<span class="line"><span>- 再画个流程图</span></span>
<span class="line"><span>- 最后给个实际产品怎么用的案例</span></span>
<span class="line"><span>- 别堆术语，读起来像在聊天</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>重点：告诉它读者是谁、要什么风格、结构怎么搭。</p><h3 id="让-ai-帮你写代码" tabindex="-1">让 AI 帮你写代码 <a class="header-anchor" href="#让-ai-帮你写代码" aria-label="Permalink to &quot;让 AI 帮你写代码&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是 TypeScript 后端。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请根据下面的接口返回结构生成类型定义和转换函数。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>注意：</span></span>
<span class="line"><span>- 不引入第三方库</span></span>
<span class="line"><span>- 可选字段要做空值保护</span></span>
<span class="line"><span>- 输出代码后补 3 个边界测试用例</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>重点：交代技术栈、边界条件、要不要测试。</p><h3 id="让-ai-帮你做分析" tabindex="-1">让 AI 帮你做分析 <a class="header-anchor" href="#让-ai-帮你做分析" aria-label="Permalink to &quot;让 AI 帮你做分析&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分析这份用户反馈。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>输出分 5 块：</span></span>
<span class="line"><span>1. 高频问题都集中在哪几类</span></span>
<span class="line"><span>2. 每类挑 3 条真实原文</span></span>
<span class="line"><span>3. 你觉得根因是什么</span></span>
<span class="line"><span>4. 产品上可以怎么改</span></span>
<span class="line"><span>5. 哪些结论需要再找数据确认</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不确定的地方单独列&quot;待验证&quot;。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>重点：别让它直接下结论，先整理归类。</p><h2 id="几个真的好用的小技巧" tabindex="-1">几个真的好用的小技巧 <a class="header-anchor" href="#几个真的好用的小技巧" aria-label="Permalink to &quot;几个真的好用的小技巧&quot;">​</a></h2><h3 id="_1-喂材料" tabindex="-1">1. 喂材料 <a class="header-anchor" href="#_1-喂材料" aria-label="Permalink to &quot;1. 喂材料&quot;">​</a></h3><p>如果你手上有参考文档，直接丢给它，然后加一句：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只基于我给的资料回答。如果资料里没有，直接说&quot;资料里没提到&quot;。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这条在做知识库问答、看合同、查制度的时候尤其救命——能挡住一多半瞎编。</p><h3 id="_2-定格式" tabindex="-1">2. 定格式 <a class="header-anchor" href="#_2-定格式" aria-label="Permalink to &quot;2. 定格式&quot;">​</a></h3><p>让它输出 JSON 就别害羞，直接写清楚结构：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;summary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;一句话总结&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;risks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;风险1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;风险2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;nextSteps&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;行动1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;行动2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>格式越明确，后面你写脚本处理的时候越省事。</p><h3 id="_3-别一口气做完" tabindex="-1">3. 别一口气做完 <a class="header-anchor" href="#_3-别一口气做完" aria-label="Permalink to &quot;3. 别一口气做完&quot;">​</a></h3><p>复杂任务拆成几步走，每一轮只推进一小步：</p>`,39)),(n(),u(h,null,{default:t(()=>[p(d,{id:"mermaid-102",class:"mermaid",graph:"flowchart%20LR%0A%20%20A%5B%22%E7%90%86%E8%A7%A3%E9%9C%80%E6%B1%82%22%5D%20--%3E%20B%5B%22%E5%88%97%E6%96%B9%E6%A1%88%22%5D%0A%20%20B%20--%3E%20C%5B%22%E4%BD%A0%E7%A1%AE%E8%AE%A4%E6%96%B9%E6%A1%88%22%5D%0A%20%20C%20--%3E%20D%5B%22%E6%89%A7%E8%A1%8C%22%5D%0A%20%20D%20--%3E%20E%5B%22%E8%87%AA%E6%A3%80%22%5D%0A"})]),fallback:t(()=>[...a[0]||(a[0]=[l(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=i('<p>你中间确认一下，比你让它从头干到尾然后推倒重来省时间得多。</p><h3 id="_4-让它老实交代" tabindex="-1">4. 让它老实交代 <a class="header-anchor" href="#_4-让它老实交代" aria-label="Permalink to &quot;4. 让它老实交代&quot;">​</a></h3><p>加这句：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不确定的地方单独列&quot;前提假设与风险&quot;，别把推测写成事实。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>能大幅减少那种&quot;说得头头是道但你一看就知道是编的&quot;的情况。</p><h2 id="我踩过的坑" tabindex="-1">我踩过的坑 <a class="header-anchor" href="#我踩过的坑" aria-label="Permalink to &quot;我踩过的坑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>坑</th><th>为什么是坑</th><th>怎么绕过去</th></tr></thead><tbody><tr><td>觉得提示词越长越好</td><td>废话多了关键信息反而被稀释</td><td>只塞跟任务相关的东西</td></tr><tr><td>只说目标不说背景</td><td>模型会脑补你的场景</td><td>上下文该给就给</td></tr><tr><td>只看输出顺不顺</td><td>顺不代表对，可能是编的</td><td>让它标注信息来源</td></tr><tr><td>一次要求做太多</td><td>做着做着就跑偏了</td><td>拆成几步，轮着来</td></tr><tr><td>完全相信输出</td><td>幻觉是个真实问题</td><td>关键结论自己再过一遍</td></tr></tbody></table><h2 id="每次发之前-问自己-6-个问题" tabindex="-1">每次发之前，问自己 6 个问题 <a class="header-anchor" href="#每次发之前-问自己-6-个问题" aria-label="Permalink to &quot;每次发之前，问自己 6 个问题&quot;">​</a></h2><ul><li>任务我讲清楚了吗？</li><li>背景我给了吗？</li><li>不能做什么我说了吗？</li><li>输出格式我定了吗？</li><li>怎么判断好坏我说了吗？</li><li>我让它不确定的时候老实交代了吗？</li></ul><p>说实话，我自己也不是每次都能写这么好。但每次翻车前回看，基本都是上面漏了某一条。</p><h2 id="一句话" tabindex="-1">一句话 <a class="header-anchor" href="#一句话" aria-label="Permalink to &quot;一句话&quot;">​</a></h2><blockquote><p>好提示词不靠玄学，靠你把目标、背景、边界和验收标准讲清楚。剩下的事，交给模型。</p></blockquote><hr><p><em>延伸阅读</em></p><ul><li><a href="https://developers.openai.com/api/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI：Prompt Engineering</a></li><li><a href="https://www.promptingguide.ai/" target="_blank" rel="noreferrer">Prompt Engineering Guide</a></li><li><a href="https://learn.deeplearning.ai/courses/chatgpt-prompt-eng/information" target="_blank" rel="noreferrer">DeepLearning.AI：ChatGPT Prompt Engineering for Developers</a></li></ul>',15))])}const C=o(b,[["render",m]]);export{A as __pageData,C as default};
